field.text:
checkpoint("cooking_for_5", "gather_preferences", { done: true })

var knowledge = loadKnowledge({
  "cooking": {
    "cuisine": {
      "type": {
        "japanese": true
      }
    },
    "dietary": {
      "restriction": {
        "vegetarian": true
      }
    },
    "technique": {
      "method": {
        "saute": true
      }
    }
  },
  "nutrition": {
    "macronutrients": {
      "type": {
        "protein": true,
        "carbohydrates": true,
        "fats": true
      }
    },
    "meal-planning": {
      "strategy": {
        "plate-method": true,
        "batch-prep": true,
        "calorie-tracking": true
      }
    }
  }
})

await stop(knowledge)

checkpoint("cooking_for_5", "load_knowledge", { loaded: true })
var baseRecipe = { name: "Vegetarian Japanese Sauté Bowl", ingredients: [ "2 cups short-grain rice", "1 block firm tofu (14oz), pressed and cubed", "2 tbsp soy sauce", "1 tbsp mirin", "1 tsp sesame oil", "2 cups mixed mushrooms (shiitake, button), sliced", "1 bell pepper, julienned", "1 cup snap peas", "3 green onions, chopped", "2 cloves garlic, minced", "1 tsp fresh ginger, grated", "1 tbsp vegetable oil for sautéing", "Sesame seeds for garnish" ], steps: [ "Cook rice according to package directions (usually 1:1.5 rice:water ratio)", "Press tofu for 15 minutes to remove excess water, then cube", "Mix soy sauce, mirin, and sesame oil for the sauce", "Heat vegetable oil in a large skillet over high heat", "Sauté tofu cubes until golden brown on all sides, remove and set aside", "In the same pan, sauté garlic and ginger for 30 seconds", "Add mushrooms and sauté until softened", "Add bell pepper and snap peas, sauté until crisp-tender", "Return tofu to the pan, add sauce, and toss to coat", "Serve over rice, garnish with green onions and sesame seeds" ], servings: 4, cuisine: "japanese", method: "saute" }
var scaledIngredients = scaleIngredients(baseRecipe.ingredients, 5/4)
await stop({ baseRecipe, scaledIngredients })

checkpoint("cooking_for_5", "create_recipe", { recipe: baseRecipe })

var nutritionEstimate = {
  protein: 45, // grams (from tofu and vegetables)
  carbs: 120, // grams (primarily from rice)
  fat: 15 // grams (from oils and tofu)
}

var calories = estimateCalories(nutritionEstimate.protein, nutritionEstimate.carbs, nutritionEstimate.fat)

await stop({ nutritionEstimate, calories })

checkpoint("cooking_for_5", "calculate_nutrition", { nutrition: calories })

var groceryList = buildGroceryList([{
  name: baseRecipe.name,
  ingredients: scaledIngredients
}])

await stop(groceryList)

checkpoint("cooking_for_5", "gather_preferences", { done: true })

var knowledge = loadKnowledge({
